import { validateEcologyGraphSnapshot } from '../ecology-graph-snapshot';

const valid = {
  schemaVersion: '1.0.0' as const,
  domain: 'pollination_pilot_v0',
  graph_id: 'site-north-2026q1',
  exported_at: '2026-04-15T12:00:00.000Z',
  nodes: [
    { id: 'a', taxon: 'Apis mellifera' },
    { id: 'b', taxon: 'Rubus idaeus' },
  ],
  edges: [
    {
      u: 'a',
      v: 'b',
      weight: 0.42,
      weight_ci: [0.31, 0.53] as const,
      provenance: 'survey' as const,
    },
  ],
};

export default function law(): void {
  if (!validateEcologyGraphSnapshot(valid).ok) {
    throw new Error('expected valid snapshot');
  }
  if (validateEcologyGraphSnapshot({ ...valid, nodes: [{ id: 'x' }, { id: 'x' }] }).ok) {
    throw new Error('expected duplicate id rejection');
  }
  if (
    validateEcologyGraphSnapshot({
      ...valid,
      edges: [{ u: 'a', v: 'nope', provenance: 'survey' as const }],
    }).ok
  ) {
    throw new Error('expected bad edge endpoint');
  }
}
